type Tone = 'primary' | 'secondary';

type MuscleMapSvgProps = {
  regionTones: Map<string, Tone>;
  className: string;
};

// TODO(POTOK): Replace temporary MVP anatomy paths with final designer-approved SVG muscle regions.
// Current component is functionally stable, but visual anatomy is not final.

const BASE_FILL = '#F4F6F9';
const BASE_STROKE = '#C9D2DE';
const PRIMARY_FILL = '#E34A5A';
const SECONDARY_FILL = '#F5A3B0';
const PRIMARY_STROKE = '#D23E4F';
const SECONDARY_STROKE = '#E795A2';

function getToneColors(tone?: Tone) {
  if (tone === 'primary') {
    return { fill: PRIMARY_FILL, stroke: PRIMARY_STROKE };
  }

  if (tone === 'secondary') {
    return { fill: SECONDARY_FILL, stroke: SECONDARY_STROKE };
  }

  return { fill: BASE_FILL, stroke: BASE_STROKE };
}

